-SearchSolution FreePoseSearch::findValidOrientation(const costmap_2d::Costmap2D& costmap_2d,
-                                                    const std::vector<geometry_msgs::Point>& footprint,
-                                                    const geometry_msgs::Pose2D& pose_2d, const SearchConfig& config,
